const axios = require('axios');
const issueId = $ticket;
const commentText = $comment;
try {
  const auth = 'Basic ' + Buffer.from($vars.ATLASSIAN_EMAIL + ':' + $vars.ATLASSIAN_TOKEN).toString('base64');
  const headers = { 'Authorization': auth, 'Accept': 'application/json', 'Content-Type': 'application/json' };

  const commentBody = { body: { type: "doc", version: 1, content: [{ type: "paragraph", content: [{ type: "text", text: commentText }] }] }};
  await axios.post(`${$vars.ATLASSIAN_HOST}/rest/api/3/issue/${issueId}/comment`, commentBody, { headers });

  await axios.post(`${$vars.ATLASSIAN_HOST}/rest/api/3/issue/${issueId}/transitions`, { transition: { id: "41" } }, { headers });

  return "SUCCESS! Successfully commented and transitioned issue " + issueId + " to Done.";
} catch (e) {
  return "ERROR: " + (e.response ? e.response.status : e.message);
}
